mapper.select:
SELECT tr.*, tr.textbook_version_number AS textbookVersionNumber, COALESCE(t.name, s.name, su.username) AS creatorName, COALESCE(t2.name, s2.name, su2.nickname) AS operatorName FROM textbook_review tr LEFT JOIN teacher t ON tr.creator = t.user_id LEFT JOIN student s ON tr.creator = s.user_id LEFT JOIN sys_tbuser su ON tr.creator = su.id LEFT JOIN teacher t2 ON tr.operator = t2.user_id LEFT JOIN student s2 ON tr.operator = s2.user_id LEFT JOIN sys_tbuser su2 ON tr.operator = su2.id
AND tr.textbook_id = #{textbookId}
ORDER BY tr.add_datetime DESC
